83	// Custom Function Signature Parsing for CudaTile Operations
84	//===----------------------------------------------------------------------===//
85	
86	// TODO: Leverage upstream changes to strip !cuda_tile. prefix.
87	/// Custom function signature parsing that uses parseCudaTileType to support
88	/// both short-form (tile<ptr<f32>>) and long-form
89	/// (!cuda_tile.tile<ptr<f32>>) types within OpAsmOpInterface default
90	/// dialect context.
91	///
92	/// Standard MLIR parseFunctionSignatureWithArguments() uses generic type
93	/// parsing that ignores OpAsmOpInterface::getDefaultDialect(), breaking
94	/// short-form type resolution within cuda_tile.module operations.
95	
96	/// Validates consistent SSA name usage across function arguments.
97	static mlir::LogicalResult validateSSANameConsistency(
98	    mlir::OpAsmParser &parser, mlir::SMLoc loc, bool hasSSAName,
99	    llvm::ArrayRef<mlir::OpAsmParser::Argument> existingArgs) {
100	  if (existingArgs.empty())
101	    return mlir::success();
102	
103	  bool prevHasSSAName = !existingArgs.back().ssaName.name.empty();
104	  if (hasSSAName != prevHasSSAName) {
105	    return parser.emitError(loc, hasSSAName
106	                                     ? "expected type instead of SSA identifier"
107	                                     : "expected SSA identifier");
108	  }
109	  return mlir::success();
110	}
111	
112	/// Parses a single function argument with cuda_tile type support.
113	static mlir::ParseResult parseSingleArgument(
114	    mlir::OpAsmParser &parser,
115	    llvm::SmallVectorImpl<mlir::OpAsmParser::Argument> &arguments) {
116	  mlir::OpAsmParser::Argument arg;
117	  arg.ssaName.location = parser.getCurrentLocation();
118	
119	  // Parse optional SSA name
120	  auto ssaResult = parser.parseOptionalOperand(arg.ssaName);
121	  bool hasSSAName = ssaResult.has_value();
122	
123	  if (hasSSAName) {
124	    if (mlir::failed(ssaResult.value()) || parser.parseColon())
125	      return mlir::failure();
126	  }
127	
128	  // Validate consistent SSA name usage
129	  if (mlir::failed(validateSSANameConsistency(parser, arg.ssaName.location,
130	                                              hasSSAName, arguments)))
131	    return mlir::failure();
132	
133	  // Parse type and attributes using cuda_tile-aware parser
134	  mlir::NamedAttrList attrs;
135	  if (parseCudaTileType(parser, arg.type) ||
136	      parser.parseOptionalAttrDict(attrs) ||
137	      parser.parseOptionalLocationSpecifier(arg.sourceLoc))
138	    return mlir::failure();
139	
140	  arg.attrs = attrs.getDictionary(parser.getContext());
141	  arguments.push_back(arg);
142	  return mlir::success();
143	}
144	
145	/// Parses function argument list with variadic support.
146	static mlir::ParseResult parseFunctionArgumentList(
147	    mlir::OpAsmParser &parser, bool allowVariadic,
148	    llvm::SmallVectorImpl<mlir::OpAsmParser::Argument> &arguments,
149	    bool &isVariadic) {
150	  isVariadic = false;
151	
152	  return parser.parseCommaSeparatedList(
153	      mlir::OpAsmParser::Delimiter::Paren, [&]() -> mlir::ParseResult {
154	        if (isVariadic)
155	          return parser.emitError(
156	              parser.getCurrentLocation(),
157	              "variadic arguments must be at end of argument list");
158	
159	        // Handle variadic ellipsis
160	        if (allowVariadic && mlir::succeeded(parser.parseOptionalEllipsis())) {
161	          isVariadic = true;
162	          return mlir::success();
163	        }
164	
165	        return parseSingleArgument(parser, arguments);
166	      });
167	}
