169	/// Parses type and attribute pairs for function results.
170	static mlir::ParseResult
171	parseTypeAndAttrList(mlir::OpAsmParser &parser,
172	                     llvm::SmallVectorImpl<mlir::Type> &types,
173	                     llvm::SmallVectorImpl<mlir::DictionaryAttr> &attrs) {
174	  return parser.parseCommaSeparatedList([&]() -> mlir::ParseResult {
175	    types.emplace_back();
176	    attrs.emplace_back();
177	    mlir::NamedAttrList attrList;
178	    if (parseCudaTileType(parser, types.back()) ||
179	        parser.parseOptionalAttrDict(attrList))
180	      return mlir::failure();
181	    attrs.back() = attrList.getDictionary(parser.getContext());
182	    return mlir::success();
183	  });
184	}
185	
186	/// Parses function result list (single type or parenthesized type list).
187	static mlir::ParseResult parseFunctionResultList(
188	    mlir::OpAsmParser &parser, llvm::SmallVectorImpl<mlir::Type> &resultTypes,
189	    llvm::SmallVectorImpl<mlir::DictionaryAttr> &resultAttrs) {
190	  if (mlir::failed(parser.parseOptionalLParen())) {
191	    // Single result type (no parentheses)
192	    mlir::Type resultType;
193	    if (parseCudaTileType(parser, resultType))
194	      return mlir::failure();
195	    resultTypes.push_back(resultType);
196	    resultAttrs.emplace_back();
197	    return mlir::success();
198	  }
199	
200	  // Parenthesized result list
201	  if (mlir::succeeded(parser.parseOptionalRParen()))
202	    return mlir::success(); // Empty result list
203	
204	  if (parseTypeAndAttrList(parser, resultTypes, resultAttrs))
205	    return mlir::failure();
206	  return parser.parseRParen();
207	}
