211	/// Main function signature parser with cuda_tile dialect support.
212	mlir::ParseResult cuda_tile::parseFunctionSignatureWithArguments(
213	    mlir::OpAsmParser &parser, bool allowVariadic,
214	    llvm::SmallVectorImpl<mlir::OpAsmParser::Argument> &arguments,
215	    bool &isVariadic, llvm::SmallVectorImpl<mlir::Type> &resultTypes,
216	    llvm::SmallVectorImpl<mlir::DictionaryAttr> &resultAttrs) {
217	  if (parseFunctionArgumentList(parser, allowVariadic, arguments, isVariadic))
218	    return mlir::failure();
219	  if (mlir::succeeded(parser.parseOptionalArrow()))
220	    return parseFunctionResultList(parser, resultTypes, resultAttrs);
221	  return mlir::success();
222	}
