224	/// Print function signature with cuda_tile dialect type support.
225	static void printFunctionSignatureWithCudaTileTypes(
226	    OpAsmPrinter &printer, TypeRange argTypes, ArrayAttr argAttrs,
227	    bool isVariadic, TypeRange resultTypes, Region *body) {
228	  printer << '(';
229	  for (unsigned i = 0, e = argTypes.size(); i < e; ++i) {
230	    if (i > 0)
231	      printer << ", ";
232	    auto arg = body->getArgument(i);
233	    ArrayRef<NamedAttribute> attrs;
234	    if (argAttrs)
235	      attrs = llvm::cast<DictionaryAttr>(argAttrs[i]).getValue();
236	    printer.printOperand(arg);
237	    printer << ": ";
238	    printCudaTileType(printer, arg.getType());
239	  }
240	
241	  if (isVariadic) {
242	    if (!argTypes.empty())
243	      printer << ", ";
244	    printer << "...";
245	  }
246	
247	  printer << ')';
248	
249	  if (!resultTypes.empty()) {
250	    printer << " -> ";
251	    if (resultTypes.size() == 1) {
252	      printCudaTileType(printer, resultTypes[0]);
253	    } else {
254	      printer << '(';
255	      llvm::interleaveComma(resultTypes, printer, [&](Type resultType) {
256	        printCudaTileType(printer, resultType);
257	      });
258	      printer << ')';
259	    }
260	  }
261	}
