263	/// Main function signature parser with cuda_tile dialect support, extracting
264	/// attributes and region from FunctionOpInterface
265	void cuda_tile::printFunctionSignatureWithCudaTileTypes(OpAsmPrinter &printer,
266	                                                        Operation *op,
267	                                                        TypeRange inputs,
268	                                                        TypeRange results) {
269	  auto funcOp = dyn_cast<FunctionOpInterface>(op);
270	  ::printFunctionSignatureWithCudaTileTypes(
271	      printer, inputs, funcOp.getArgAttrsAttr(),
272	      /*isVariadic=*/false, results, &funcOp.getFunctionBody());
273	}
