279	// TODO: Leverage upstream changes to strip !cuda_tile. prefix.
280	static LogicalResult validateIntegerBounds(OpAsmParser &parser, int64_t intVal,
281	                                           Type elementType, SMLoc loc) {
282	  if (elementType.isInteger(1)) {
283	    // Union of signed [-1,1] and unsigned [0,1] = [-1,1]
284	    if (intVal < -1 || intVal > 1)
285	      return parser.emitError(loc, "integer constant out of range for type");
286	  } else if (elementType.isInteger(8)) {
287	    // Union of signed [-128,127] and unsigned [0,255] = [-128,255]
288	    if (intVal < -128 || intVal > 255)
289	      return parser.emitError(loc, "integer constant out of range for type");
290	  } else if (elementType.isInteger(16)) {
291	    // Union of signed [-32768,32767] and unsigned [0,65535] = [-32768,65535]
292	    if (intVal < -32768 || intVal > 65535)
293	      return parser.emitError(loc, "integer constant out of range for type");
294	  } else if (elementType.isInteger(32)) {
295	    // Union of signed [-2^31,2^31-1] and unsigned [0,2^32-1] = [-2^31,2^32-1]
296	    if (intVal < -2147483648LL || intVal > 4294967295LL)
297	      return parser.emitError(loc, "integer constant out of range for type");
298	  } else if (elementType.isInteger(64)) {
299	    // For i64, int64_t already covers the full signed range [-2^63,2^63-1]
300	    // The unsigned range [0,2^64-1] extends beyond int64_t, so we accept all
301	    // int64_t values negative values will be interpreted as large unsigned
302	    // values in two's complement
303	  }
304	  return success();
305	}
306	
307	static bool isValidDenseElementType(Type elementType) {
308	  return elementType.isInteger(1) ||            // i1
309	         elementType.isInteger(8) ||            // i8
310	         elementType.isInteger(16) ||           // i16
311	         elementType.isInteger(32) ||           // i32
312	         elementType.isInteger(64) ||           // i64
313	         elementType.isF16() ||                 // f16
314	         elementType.isBF16() ||                // bf16
315	         elementType.isF32() ||                 // f32
316	         elementType.isF64() ||                 // f64
317	         elementType.isTF32() ||                // tf32
318	         isa<Float8E4M3FNType>(elementType) ||  // f8E4M3FN
319	         isa<Float8E5M2Type>(elementType) ||    // f8E5M2
320	         isa<Float8E8M0FNUType>(elementType) || // f8E8M0FNU
321	         isa<Float4E2M1FNType>(elementType);    // f4E2M1FN
322	}
323	
324	// Parse format: constant <f32: 0x7F800000> : tile<f32>
325	static ParseResult parseDenseTypedElementsAttr(OpAsmParser &parser,
326	                                                 DenseTypedElementsAttr &attr,
327	                                                 Type &resultType) {
328	  if (parser.parseLess())
329	    return failure();
330	
331	  // We use the prefix element type to understand how to parse the dense values.
332	  Type prefixElementType;
333	  if (parseCudaTileType(parser, prefixElementType))
334	    return parser.emitError(parser.getCurrentLocation())
335	           << "expect element type to be one of i1 or i8 or i16 or i32 or i64 "
336	              "or f16 "
337	              "or bf16 or f32 or f64 or tf32 or f8E4M3FN or f8E5M2 or "
338	              "f8E8M0FNU or f4E2M1FN values, but got "
339	           << prefixElementType;
340	
341	  // Validate that prefixElementType is one of the allowed types
342	  if (!isValidDenseElementType(prefixElementType)) {
343	    return parser.emitError(parser.getCurrentLocation())
344	           << "expect element type to be one of i1 or i8 or i16 or i32 or i64 "
345	              "or f16 "
346	              "or bf16 or f32 or f64 or tf32 or f8E4M3FN or f8E5M2 or "
347	              "f8E8M0FNU or f4E2M1FN values, but got "
348	           << prefixElementType;
349	  }
350	
351	  bool isInteger = prefixElementType.isIntOrIndex();
352	
353	  if (parser.parseColon())
354	    return failure();
355	
356	  SmallVector<APFloat> floatValues;
357	  SmallVector<int64_t> integerValues;
358	  SmallVector<int64_t> inferredShape;
359	
360	  //===----------------------------------------------------------------------===//
361	  // Helper Functions for Enhanced Dense Parsing
362	  //===----------------------------------------------------------------------===//
363	
364	  // Parse a single numeric value (integer or float, positive or negative)
365	  auto parseNumericValue = [&]() -> ParseResult {
366	    SMLoc loc = parser.getCurrentLocation();
367	
368	    if (isInteger) {
369	      // Error when true or false passed to an int that is not an i1
370	      if (prefixElementType.getIntOrFloatBitWidth() != 1 &&
371	          (succeeded(parser.parseOptionalKeyword("true")) ||
372	           succeeded(parser.parseOptionalKeyword("false"))))
373	        return parser.emitError(loc, "expected integer value");
374	
375	      int64_t intVal;
376	      if (parser.parseInteger(intVal))
377	        return parser.emitError(loc, "expected integer value");
378	
379	      // Validate the integer fits in the target type
380	      if (failed(validateIntegerBounds(parser, intVal, prefixElementType, loc)))
381	        return failure();
382	
383	      integerValues.push_back(intVal);
384	      return success();
385	    }
386	
387	    assert(!isInteger && "expect integer but parsing a float");
388	    const llvm::fltSemantics *targetSemantics = &APFloat::IEEEdouble();
389	    APFloat floatValue(APFloat::IEEEdouble());
390	    if (auto floatType = dyn_cast<FloatType>(prefixElementType))
391	      targetSemantics = &floatType.getFloatSemantics();
392	
393	    if (succeeded(parser.parseFloat(*targetSemantics, floatValue))) {
394	      floatValues.push_back(floatValue);
395	      return success();
396	    }
397	    return failure();
398	  };
