282	def CudaTile_DivByAttr : CudaTileAttrDef<"DivBy", "div_by", "13.1",
283	    [DeclareAttrInterfaceMethods<CudaTile_AssumePredicateAttrInterface>]> {
284	
285	  let description = [{
286	    .. code-block:: mlir
287	
288	      div_by< $divisor (, every $every^ along $along)?>
289	
290	    The :code:`div_by` attribute must be used as a predicate for :code:`cuda_tile.assume`
291	    ops. The predicated value must be a :code:`tile` of integers or pointers, or
292	    a :code:`tensor_view`.
293	
294	    If the predicated value is a :code:`tile`, the attribute indicates that some
295	    elements of the :code:`tile` are divisible by :code:`divisor`. If the predicated value
296	    is a :code:`tensor_view` the attribute indicates that the base address of the :code:`tensor_view` is
297	    divisible by :code:`divisor`. :code:`divisor` must be a positive power of :code:`2`.
298	
299	    The :code:`every` and :code:`along` attributes control which elements are assumed to
300	    satisfy the divisibility property. When splitting the tensor in groups of
301	    size :code:`every` along dimension :code:`along`, the first element of each group is
302	    assumed to satisfy the divisibility property. The other elements are
303	    assumed to be monotonically increasing by :code:`1` within the group. In case
304	    of a :code:`tile` of pointers, the elements are assumed to be monotonically
305	    increasing by the byte width of the pointee type. The size of the last
306	    group may be smaller than :code:`every`.
307	
308	    The :code:`every` and :code:`along` attributes are optional. When missing, they are
309	    assumed to have a default value of :code:`1` and :code:`0` in case of a :code:`tile`.
310	    I.e., all elements of the :code:`tile` are assumed to satisfy the divisibility
311	    property. (The value of :code:`along` does not matter in that case.) If the
312	    predicated value is a :code:`tensor_view` or a 0D :code:`tile`, :code:`every` and :code:`along` cannot be
313	    used.
314	
315	    :code:`every`, and :code:`along` must be used together. If one is specified,
316	    so must be the other.
317	
318	    .. note::
319	
320	      If the predicated value is a tile of integers, :code:`every` is a property of
321	      the signed interpretation of the integer values. Otherwise, it is a
322	      property of the unsigned integer interpretation. E.g., :code:`every = 4`
323	      is incorrect for the following sequence of "i8" values (written in binary
324	      form) because they wrap around when interpreted as signed integers:
325	      :code:`[01111110, 01111111, 10000000, 10000001]`. :code:`every = 2` would
326	      be correct.
327	
328	    The examples below demonstrate tensors that satisfy the assumed properties.
329	  }];
330	
331	  let mlirExamples = [
332	    [{
333	      // Example 1: Each pointer is divisible by 16.
334	      // [ 0x10, 0x20, 0x80, 0x10, 0x0, 0x120, ... ]
335	      %0 = cuda_tile.assume #cuda_tile.div_by<16>, %ptrs
336	          : !cuda_tile.tile<128x!cuda_tile.ptr<f32>>
337	      // Note: Equivalent to #cuda_tile.div_by<16, every 1 along 0>.
338	    }],
339	    [{
340	    // Example 2: Each integer is divisible by 4.
341	    // [ 16, 24, 8, 4, 12, 12, 0, 16, ... ]
342	    %0 = cuda_tile.assume #cuda_tile.div_by<4>, %t
343	        : !cuda_tile.tile<128xi32>
344	    }],
345	    [{
346	    // Example 3: Group size [4].
347	    // [7, 8, 9, 10, 23, 24, 25, 26, 0, 1, 2, 3, ...]
348	    %0 = cuda_tile.assume #cuda_tile.div_by<1, every 4 along 0>, %t
349	        : !cuda_tile.tile<128xi32>
350	    }],
351	    [{
352	    // Example 4: 2-d Group size [1, 4] with divisibility 4.
353	    // [ [  4,  5,  6,  7, 12, 13, 14, 15 ],
354	    //   [  8,  9, 10, 11, 24, 25, 26, 27 ],
355	    //   [ 24, 25, 26, 27, 64, 65, 66, 67 ],
