390	  let description = [{
391	    .. code-block:: mlir
392	
393	      #same_elements< $values >
394	
395	    The :code:`same_elements` attribute must be used as a predicate for
396	    :code:`cuda_tile.assume`. The predicated value must be a tensor of integers or
397	    pointers.
398	
399	    :code:`same_elements` is specified for each dimension. A value of C for a
400	    dimension of size N indicates that, after dividing the respective
401	    dimension into N/C groups of size C, each group consists of the same
402	    elements. As N/C may not divide evenly, the last group may have fewer
403	    than C elements.
404	
405	    If the "same elements" property does not hold along a dimension, the
406	    respective value should be set to 1.
407	    :code:`#cuda_tile.same_elements<[1, 1, ..., 1]>` is a correct predicate for any
408	    tensor of integers or pointers, where the number of ones matches the rank
409	    of the tensor. (Size-1 groups always have the same elements.)
410	  }];
411	
412	  let mlirExamples = [[{
413	    // Integer tensor with same elements.
414	    %0 = cuda_tile.constant <i16: [[0, 0, 0, 0, 10, 10, 10, 10],
